+import { NextRequest, NextResponse } from 'next/server'
+import { AuditEngine } from '@/lib/audit-engine'
+import dns from 'node:dns/promises'
+import { normalizeInputUrl, isHostBlocked, isIpPrivate } from '@/lib/url-utils'
+
+export const runtime = 'nodejs'
+
+// Simple in-memory per-IP rate limiter (best-effort; consider external store for production)
+type RateState = { count: number; windowStart: number }
+const RATE_WINDOW_MS = 60_000 // 1 minute
+const RATE_MAX = 5 // 5 requests/minute/IP
+const rateMap = new Map<string, RateState>()
+
+function getClientIp(req: NextRequest): string {
+  // NextRequest.ip may be populated by the platform
+  const direct = (req as any).ip as string | undefined
+  if (direct) return direct
+  const fwd = req.headers.get('x-forwarded-for') || ''
+  return fwd.split(',')[0].trim() || 'unknown'
+}
+
+function checkRateLimit(ip: string): boolean {
+  const now = Date.now()
+  const cur = rateMap.get(ip)
+  if (!cur || now - cur.windowStart > RATE_WINDOW_MS) {
+    rateMap.set(ip, { count: 1, windowStart: now })
+    return true
+  }
+  if (cur.count >= RATE_MAX) return false
+  cur.count += 1
+  return true
+}
+
+async function resolveAll(host: string): Promise<string[]> {
+  const out: string[] = []
+  try {
+    const a = await dns.resolve4(host)
+    out.push(...a)
+  } catch {}
+  try {
+    const aaaa = await dns.resolve6(host)
+    out.push(...aaaa)
+  } catch {}
+  return out
+}
+
+async function withTimeout<T>(p: Promise<T>, ms: number): Promise<T> {
+  return await Promise.race([
+    p,
+    new Promise<T>((_, reject) => setTimeout(() => reject(new Error('Audit timed out')), ms)),
+  ])
+}
+
+export async function POST(request: NextRequest) {
+  try {
+    // Optional API key auth (enabled when AUDIT_API_KEY is set)
+    const requiredKey = process.env.AUDIT_API_KEY
+    if (requiredKey) {
+      const auth = request.headers.get('authorization') || ''
+      if (auth !== `Bearer ${requiredKey}`) {
+        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
+      }
+    }
+
+    const ip = getClientIp(request)
+    if (!checkRateLimit(ip)) {
+      return NextResponse.json({ error: 'Too many requests' }, { status: 429 })
+    }
+
+    let body: any
+    try {
+      body = await request.json()
+    } catch {
+      return NextResponse.json({ error: 'Invalid request body' }, { status: 400 })
+    }
+
+    if (!body || typeof body.url !== 'string') {
+      return NextResponse.json({ error: 'URL is required' }, { status: 400 })
+    }
+
+    // Normalize before validation to align with client behavior
+    let normalized: string
+    try {
+      normalized = normalizeInputUrl(body.url)
+    } catch (e: any) {
+      const msg = e?.message === 'URL not allowed' ? e.message : 'Invalid URL format'
+      return NextResponse.json({ error: msg }, { status: 400 })
+    }
+
+    const parsed = new URL(normalized)
+    const host = parsed.hostname
+
+    // Block obvious dangerous hosts
+    if (isHostBlocked(host)) {
+      console.warn('Blocked SSRF attempt (host):', host)
+      return NextResponse.json({ error: 'URL not allowed' }, { status: 400 })
+    }
+
